func TestCiliumEnableHostFirewallOptionAndTemplate(t *testing.T) {
	cluster := &kopsapi.Cluster{
		Spec: kopsapi.ClusterSpec{
			Networking: kopsapi.NetworkingSpec{
				Cilium: &kopsapi.CiliumNetworkingSpec{
					EnableHostFirewall: fi.PtrTo(true),
				},
			},
		},
	}

	ob := &CiliumOptionsBuilder{}
	if err := ob.BuildOptions(cluster); err != nil {
		t.Fatalf("failed to build options: %v", err)
	}
	if cluster.Spec.Networking.Cilium.EnableHostFirewall == nil || !*cluster.Spec.Networking.Cilium.EnableHostFirewall {
		t.Fatalf("EnableHostFirewall was not preserved as true")
	}

	templates, err := templates.LoadTemplates(t.Context(), cluster, models.NewAssetPath("cloudup/resources"))
	if err != nil {
		t.Fatalf("failed to load templates: %v", err)
	}
	ciliumTemplate := templates.Find("addons/networking.cilium.io/k8s-1.16-v1.15.yaml")
	if ciliumTemplate == nil {
		t.Fatalf("failed to find cilium addon template")
	}
	manifest, err := ciliumTemplate.Execute(cluster.Spec.Networking.Cilium)
	if err != nil {
		t.Fatalf("failed to execute cilium addon template: %v", err)
	}
	manifestString := string(manifest)
	if !strings.Contains(manifestString, `enable-host-firewall: "true"`) {
		t.Fatalf("cilium manifest did not contain enable-host-firewall true")
	}
}

